// Extract & Filter URLs - V2 з розширеними паттернами
var scanResult = $input.item.json;
var allResults = scanResult.all_results || [];
var editFieldsData = $('Edit Fields').first().json;
var companyName = editFieldsData.companyName || 'Unknown';
var companyUrl = editFieldsData.companyUrl || '';
console.log('Extract URLs - Company:', companyName, 'Total URLs:', allResults.length);
var categories = {
blog: /\/(blog|blogs|article|articles|post|posts|insights|journal|novosti|stati|publikacii)/i,
news: /\/(news|press|announcements|newsroom|events|meropriyatiya|sobytiya)/i,
reviews: /\/(review|reviews|testimonial|testimonials|customer-stories|success-stories|case-studies|otzyvy|klienty|use_mango|clients)/i,
pricing: /\/(pricing|price|prices|plans|tarif|cost|tariffs|ceny|stoimost)/i,
features: /\/(features|feature|capabilities|vozmozhnosti|resheniya|funktsii|marketplace|integraciya)/i
};
var categorizedUrls = [];
var seenUrls = new Set();
for (var i = 0; i < allResults.length; i++) {
var result = allResults[i];
var url = result.url || '';
if (result.has_errors || seenUrls.has(url)) continue;
seenUrls.add(url);
if (url.match(/\/$/)) {
var path = url.replace(/https?:\/\/[^\/]+/, '');
if (path === '/' || path === '/about/' || path === '/promo/' || path === '/products/') continue;
}
for (var cat in categories) {
if (categories[cat].test(url)) {
categorizedUrls.push({
url: url,
category: cat,
status_code: result.status_code,
companyName: companyName,
companyUrl: companyUrl
});
break;
}
}
}
console.log('Filtered URLs:', categorizedUrls.length, 'Categories:', categorizedUrls.map(function(u) { return u.category; }).join(', '));
if (categorizedUrls.length === 0) {
return [{ json: { url: '', category: 'none', status_code: 0, companyName: companyName, companyUrl: companyUrl } }];
}
return categorizedUrls.map(function(item) { return { json: item }; });

// Parse Page Content - V4 (fixed: data instead of body)
var inputItem = $input.item.json;
var html = inputItem.data || inputItem.body || '';
var setFieldsData = $('Set Fields Before Fetch').item.json;
var companyName = setFieldsData.companyName || 'Unknown';
var companyUrl = setFieldsData.companyUrl || '';
var pageUrl = setFieldsData.pageUrl || '';
var category = setFieldsData.category || 'unknown';
function cleanText(text) {
if (!text) return '';
return text.replace(/&nbsp;/gi, ' ').replace(/&amp;/gi, '&').replace(/&lt;/gi, '<').replace(/&gt;/gi, '>').replace(/&#\d+;/g, '').replace(/\s+/g, ' ').trim();
}
var cleanHtml = html.replace(/<header[^>]*>[\s\S]*?<\/header>/gi, '').replace(/<nav[^>]*>[\s\S]*?<\/nav>/gi, '').replace(/<footer[^>]*>[\s\S]*?<\/footer>/gi, '').replace(/<aside[^>]*>[\s\S]*?<\/aside>/gi, '').replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '').replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '');
var titleMatch = html.match(/<title[^>]*>([^<]+)<\/title>/i);
var title = titleMatch ? cleanText(titleMatch[1]) : null;
var descMatch = html.match(/<meta[^>]*name=["']description["'][^>]*content=["']([^"']+)["']/i);
var description = descMatch ? cleanText(descMatch[1]) : null;
var h1Matches = cleanHtml.match(/<h1[^>]*>([\s\S]*?)<\/h1>/gi) || [];
var h2Matches = cleanHtml.match(/<h2[^>]*>([\s\S]*?)<\/h2>/gi) || [];
var h3Matches = cleanHtml.match(/<h3[^>]*>([\s\S]*?)<\/h3>/gi) || [];
var h1Tags = h1Matches.map(function(h) { return cleanText(h.replace(/<[^>]+>/g, '')); }).filter(function(t) { return t.length > 2 && t.length < 200; });
var h2Tags = h2Matches.map(function(h) { return cleanText(h.replace(/<[^>]+>/g, '')); }).filter(function(t) { return t.length > 5 && t.length < 200; }).slice(0, 10);
var h3Tags = h3Matches.map(function(h) { return cleanText(h.replace(/<[^>]+>/g, '')); }).filter(function(t) { return t.length > 5 && t.length < 200; }).slice(0, 15);
var categoryData = {};
if (category === 'blog' || category === 'news') {
var articles = [];
var seen = new Set();
var articlePatterns = [/<article[^>]*>([\s\S]*?)<\/article>/gi, /<div[^>]*class=["'][^"']*(?:post|entry|blog-item|news-item|article)[^"']*["'][^>]*>([\s\S]*?)<\/div>/gi];
for (var p = 0; p < articlePatterns.length && articles.length < 15; p++) {
var match;
articlePatterns[p].lastIndex = 0;
while ((match = articlePatterns[p].exec(cleanHtml)) !== null && articles.length < 15) {
var content = match[1] || match[0];
var tMatch = content.match(/<h[1-4][^>]*>([\s\S]*?)<\/h[1-4]>/i);
var t = tMatch ? cleanText(tMatch[1].replace(/<[^>]+>/g, '')) : null;
if (t && t.length > 10 && !seen.has(t.toLowerCase())) {
seen.add(t.toLowerCase());
articles.push({ title: t, preview: cleanText(content.replace(/<[^>]+>/g, ' ')).substring(0, 200) });
}
}
}
if (articles.length === 0) {
h2Tags.concat(h3Tags).forEach(function(t) {
if (!seen.has(t.toLowerCase()) && articles.length < 15) {
seen.add(t.toLowerCase());
articles.push({ title: t, preview: '' });
}
});
}
categoryData.articles = articles;
categoryData.topics = h2Tags.slice(0, 10);
} else if (category === 'reviews') {
categoryData.topics = h2Tags.concat(h3Tags).slice(0, 15);
categoryData.mainContent = cleanText(cleanHtml.replace(/<[^>]+>/g, ' ')).substring(0, 1000);
} else if (category === 'pricing') {
var priceMatches = html.match(/\d+[\s\u00a0]*(?:руб|₽|рублей|RUB)|[\$€£]\s*\d+(?:[.,]\d{2})?|\d+(?:[.,]\d{2})?\s*(?:USD|EUR|GBP|руб)/gi) || [];
categoryData.prices = [...new Set(priceMatches)].slice(0, 20);
categoryData.hasPricing = priceMatches.length > 0;
categoryData.plans = h2Tags.concat(h3Tags).filter(function(t) { return t.match(/пакет|тариф|план|price|plan|базов|стандарт|премиум|pro|enterprise/i); }).slice(0, 10);
categoryData.topics = h2Tags.slice(0, 10);
} else if (category === 'features') {
var features = [];
var featureLists = cleanHtml.match(/<ul[^>]*>[\s\S]{1,10000}?<\/ul>/gi) || [];
for (var j = 0; j < featureLists.length && features.length < 30; j++) {
var items = featureLists[j].match(/<li[^>]*>([\s\S]*?)<\/li>/gi) || [];
for (var k = 0; k < items.length && features.length < 30; k++) {
var text = cleanText(items[k].replace(/<[^>]+>/g, ''));
if (text.length > 10 && text.length < 300) features.push(text);
}
}
categoryData.features = features;
categoryData.topics = h2Tags.concat(h3Tags).slice(0, 15);
}
var mainText = cleanText(cleanHtml.replace(/<[^>]+>/g, ' ')).substring(0, 1500);
return {
url: pageUrl,
category: category,
companyName: companyName,
companyUrl: companyUrl,
metadata: { title: title, description: description, h1: h1Tags, h2: h2Tags, h3: h3Tags },
content: categoryData,
summary: mainText,
parsedAt: new Date().toISOString()
};

// Aggregate by Category - отримуємо companyName/companyUrl з input items
var allPages = $input.all();

// Отримуємо companyName та companyUrl з першого item (всі мають однакові значення)
var companyName = 'Unknown';
var companyUrl = '';

if (allPages.length > 0 && allPages[0].json) {
  companyName = allPages[0].json.companyName || 'Unknown';
  companyUrl = allPages[0].json.companyUrl || '';
}

console.log('Aggregate - Company:', companyName, 'URL:', companyUrl, 'Pages count:', allPages.length);

var byCategory = { blog: [], news: [], reviews: [], pricing: [], features: [] };

for (var i = 0; i < allPages.length; i++) {
  var pageData = allPages[i].json;
  var category = pageData.category;
  if (byCategory[category]) byCategory[category].push(pageData);
}

var stats = {};
for (var cat in byCategory) { stats[cat] = byCategory[cat].length; }

return { 
  company: companyName, 
  url: companyUrl, 
  companyName: companyName, 
  companyUrl: companyUrl, 
  totalPagesParsed: allPages.length, 
  statistics: stats, 
  categorizedData: byCategory, 
  aggregatedAt: new Date().toISOString() 
};

var response = $input.item.json;
var rawContent = response.output || response.text || '';
if (response.choices && response.choices[0] && response.choices[0].message) {
  rawContent = response.choices[0].message.content;
}
rawContent = rawContent.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
var parsedData;
try {
  parsedData = typeof rawContent === 'string' ? JSON.parse(rawContent) : rawContent;
} catch (e) {
  parsedData = { company: 'Unknown', url: '', youtubeActivity: '-', linkedinActivity: '-', facebookActivity: '-', aggregatorMentions: '-', socialMentionsCount: 0, newFeatures: [], problems: ['Error: ' + e.message], reviewInsights: '-', news: [], blogArticles: [], customerPains: [], customerWants: [], summary: 'Parsing failed' };
}
return { company: parsedData.company, url: parsedData.url, youtubeActivity: parsedData.youtubeActivity, linkedinActivity: parsedData.linkedinActivity, facebookActivity: parsedData.facebookActivity, aggregatorMentions: parsedData.aggregatorMentions, socialMentionsCount: parsedData.socialMentionsCount || 0, aiAnalysis: { newFeatures: parsedData.newFeatures, problems: parsedData.problems, reviewInsights: parsedData.reviewInsights, news: parsedData.news, blogArticles: parsedData.blogArticles, customerPains: parsedData.customerPains, customerWants: parsedData.customerWants, summary: parsedData.summary }, parsedAt: new Date().toISOString() };

// Check If Company Exists - FIXED: Find NEW data by _isNewData marker
const allInputs = $input.all();

console.log('=== CHECK IF COMPANY EXISTS ===');
console.log('Total input items:', allInputs.length);

// Шукаємо НОВІ дані по маркеру _isNewData (замість жорсткого input[0])
let newData = null;
let newDataSource = 'not found';

for (let i = 0; i < allInputs.length; i++) {
  const item = allInputs[i];
  if (item && item.json && item.json._isNewData === true) {
    newData = item.json;
    newDataSource = 'input[' + i + '] with _isNewData marker';
    break;
  }
}

// Якщо не знайшли по маркеру, шукаємо по наявності даних аналізу
if (!newData) {
  for (let i = 0; i < allInputs.length; i++) {
    const item = allInputs[i];
    if (item && item.json) {
      const data = item.json;
      // НОВІ дані мають поля аналізу
      if (data['Нові фічі'] || data['AI Summary'] || data._originalData) {
        newData = data;
        newDataSource = 'input[' + i + '] with analysis fields';
        break;
      }
    }
  }
}

// Якщо досі не знайшли, беремо перший non-empty item
if (!newData && allInputs.length > 0) {
  newData = allInputs[0].json || {};
  newDataSource = 'input[0] (fallback)';
}

console.log('New data source:', newDataSource);

const company = newData['Компанія'] || newData._originalData?.company || newData.company || 'Unknown';
const url = newData['URL'] || newData._originalData?.url || newData.url || '';

console.log('New company:', company);
console.log('New URL:', url);

// Інші inputs - це існуючі рядки з Google Sheets
const existingRows = [];
for (let i = 0; i < allInputs.length; i++) {
  const item = allInputs[i];
  if (item && item.json) {
    const data = item.json;
    // Пропускаємо нові дані, збираємо тільки існуючі рядки (з row_number або без _isNewData)
    if (data._isNewData !== true && (data.row_number || data['Компанія'] || data['Company'])) {
      existingRows.push(data);
    }
  }
}

console.log('Existing rows found:', existingRows.length);

// Шукаємо чи існує така компанія в таблиці
let foundRow = null;
let rowIndex = -1;
let matchedBy = null;

const searchCompany = String(company || '').toLowerCase().trim();
const searchUrl = String(url || '').toLowerCase().trim();

for (let i = 0; i < existingRows.length; i++) {
  const row = existingRows[i];
  const rowCompany = String(row['Компанія'] || row['Company'] || row['company'] || '').toLowerCase().trim();
  const rowUrl = String(row['URL'] || row['Url'] || row['url'] || '').toLowerCase().trim();

  if (rowCompany === searchCompany || rowUrl === searchUrl) {
    foundRow = row;
    rowIndex = i;
    matchedBy = rowCompany === searchCompany ? 'name' : 'url';
    console.log('Found existing company at index:', i, 'matched by:', matchedBy);
    break;
  }
}

// ПОВЕРТАЄМО НОВІ ДАНІ + control поля для Update/Append
const result = {
  // Всі дані з НОВОГО аналізу
  'Дата': newData['Дата'] || new Date().toISOString().split('T')[0],
  'Компанія': company,
  'URL': url,
  'Нові фічі': newData['Нові фічі'] || '-',
  'Проблеми': newData['Проблеми'] || '-',
  'Інсайти з коментарів': newData['Інсайти з коментарів'] || '-',
  'Новини (з останньої перевірки)': newData['Новини (з останньої перевірки)'] || '-',
  'Статті в блозі (з останньої перевірки)': newData['Статті в блозі (з останньої перевірки)'] || '-',
  'YouTube активність': newData['YouTube активність'] || newData.youtubeActivity || '-',
  'Facebook активність': newData['Facebook активність'] || newData.facebookActivity || '-',
  'LinkedIn активність': newData['LinkedIn активність'] || newData.linkedinActivity || '-',
  'Згадки на агрегаторах': newData['Згадки на агрегаторах'] || newData.aggregatorMentions || '-',
  'Кількість згадок в соцмережах': newData['Кількість згадок в соцмережах'] || newData.socialMentionsCount || '0',
  'Болі клієнтів з коментарів': newData['Болі клієнтів з коментарів'] || '-',
  'Хотілки клієнтів з коментарів': newData['Хотілки клієнтів з коментарів'] || '-',
  'AI Summary': newData['AI Summary'] || '-',

  // Control fields for IF node
  '_action': foundRow ? 'update' : 'append',
  '_rowId': foundRow ? (foundRow.row_number || foundRow.id || rowIndex + 2) : null,
  '_isUpdate': !!foundRow,
  '_matchInfo': foundRow ? {
    matchedBy: matchedBy,
    existingCompany: foundRow['Компанія'],
    existingUrl: foundRow['URL']
  } : null
